var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"너, 이 자식 뭐야! 언제부터 우리 뒤를 밟고 다닌 거냐?","JPN":"てめえは何だ！　いつから俺たちの後を追った？","ENG":"Huh?! What the hell are you?! How long have you been following us?!","TWN":"你這傢伙！從什麼時候開始跟蹤我們的？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"똑바로 불지 못해? 경찰 끄나풀이지? 죽여버린다, 앙?","JPN":"はっきり言え！　警察の手先なんだろ？　殺すぞ？　ああん？","ENG":"Spill it! You’re a cop, aren’t ya?! You wanna die, punk, do ya?!","TWN":"還不說實話？你是警察的走狗吧？信不信我殺了你？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"아이고, 오해라니까요, 오해. 저 같은 약골이 무슨 경찰입니까, 선생님들.","JPN":"だから、誤解ですよ、誤解。俺みたいな弱虫が警察だなんて、とんでもないです。","ENG":"Welp... This is all just a misunderstanding. I mean, c’mon. How can a scrawny guy like me even be a cop?","TWN":"哎呀，誤會了，誤會了。像我這麼弱不禁風的傢伙怎麼可能是警察呢。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"네 녀석이 우리 거래지를 며칠 전부터 어슬렁거렸다는 보고가 있었어. 그래도 발뺌할 셈이냐?","JPN":"貴様が俺たちの取引場所を数日前からウロウロしてたって報告があったんだ。それでも言い逃れるつもりか？","ENG":"We know you’ve been snooping around our trade spots. You still gonna play dumb with us?","TWN":"有報告說你這傢伙從幾天前就開始在我們的交易地點徘徊，你還不承認嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"그, 그건…… 우연이라고 해야 할까. 집이 근처라서……","JPN":"そ、それは……偶然というか。家が近くなんで……","ENG":"L-look... That’s just a coincidence! I just live around here, you know?","TWN":"那，那個…應該說是巧合吧。因為家就在附近…"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"그래? 그럼 그 카메라는 왜 찍고 있던 건데?","JPN":"そうか？　じゃあ、そのカメラは何で撮ってたんだよ。","ENG":"Oh yeah? Then what’s with the camera, huh?!","TWN":"是嗎？那你為什麼還用相機拍照？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"역시 수상해. 묻어버리는 게 좋겠어.","JPN":"やっぱり怪しいな。埋めた方がよさそうだぞ。","ENG":"I don’t like him. Let’s bury him just to be sure.","TWN":"果然有鬼，還是把他埋了吧。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"네, 네……? 뭐라고요?","JPN":"は？　え……？　何ですと？","ENG":"W-what...?","TWN":"啊，啊…？什麼？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"내일 부고란에 네 이름이 실릴 거란 뜻이지.","JPN":"明日の訃報にてめえの名前が書かれるってことだ。","ENG":"We’re sayin’ your name’s gonna show up in the news tomorrow.","TWN":"明天的訃聞上就會有你的名字。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"새삼스럽게 뭘 그래? 어차피 빈민가 뒷골목에서의 객사쯤이야 흔한 일이잖냐.","JPN":"今更なんだ？　どうせスラムの路地裏で起こる客死とか、ありふれたことだろ。","ENG":"Happens all the time in these slums. No one’s gonna bat an eye.","TWN":"這有什麼好大驚小怪的？反正貧民窟後巷死個人是常有的事。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"……치잇.","JPN":"……ちっ。","ENG":"...Tch.","TWN":"哼！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"크아악, 내 코가……!","JPN":"ぐああ、俺の鼻が……！","ENG":"Aaaargh! My nose...!","TWN":"咳啊啊，我的鼻子…！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"뭐해! 도망친다! 잡아!","JPN":"何してんだ！　逃げてるぞ！　捕まえろ！","ENG":"He’s gettin’ away! Grab him!","TWN":"幹什麼！人跑掉了！快抓住他！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_C","text":{"KOREA":"잡았다!","JPN":"捕まえた！","ENG":"Gotcha!","TWN":"抓到了！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_C","face":"UNIT_IDLE"},"C":{"char_id":"PERSON_EXTRA_NULL_MINWOO","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"크윽……","JPN":"くうっ……","ENG":"Krrgh...","TWN":"呃…"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PERSON_EXTRA_NULL_MINWOO","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_C","text":{"KOREA":"형님! 어떻게 할까요?","JPN":"兄貴！　どうしますか？","ENG":"Sir! What should I do with him?","TWN":"大哥！我們該怎麼辦？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_MEMBER_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"뭘 그런 걸 일일이 물어보고 그래! 내 코 부러진 거 안 보여?","JPN":"何を一々聞いてんだ？　俺の鼻が折れてるだろーが。","ENG":"You stupid or something?! That punk broke my nose!","TWN":"什麼都要問我！沒看到我鼻子都斷了嗎？！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"다신 일어나지 못하게 흠씬 두들겨 패버려!","JPN":"もう二度と起き上がれないように、ボッコボコにしてやれ！","ENG":"Beat him up until he can’t walk any more!","TWN":"給我打到他再也爬不起來！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_C","text":{"KOREA":"우아악!","JPN":"ぐわあっ！","ENG":"Whoa!!","TWN":"哇啊啊！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"방금 뭐였지? 사람이 날아간 거야?","JPN":"今何だったんだ？　人が飛んだのか？","ENG":"What the hell was that?! Did he just go flying?!","TWN":"剛才是什麼？有人飛出去了嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"어이, 방금 내 어깨 치고 갔잖아.","JPN":"おい、今アタシの肩にぶつかっただろう。","ENG":"Hey, you bumped into me first.","TWN":"喂，你剛才撞到我的肩膀了。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"사과도 없이 그냥 가려고?","JPN":"謝らないで行くつもりなのか？","ENG":"And you don’t even say sorry?","TWN":"都不道歉就想走？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"뭐, 뭐야, 이 여자. 겁대가릴 상실했나?","JPN":"な、なんだ、この女。頭おかしくなってんのか？","ENG":"H-huh? This chick thinks she can take me on!","TWN":"你，你這女人在搞什麼？你瘋了嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"우리 조직원을 건드리다니. 방금 네가 무슨 짓을 한 건지 자각은 있는 거냐?","JPN":"俺たちの組織員に手を出すなんてよ。今てめえが何をしたのか、わかってるのか？","ENG":"Do you even realize what you just did, little girl?!","TWN":"竟敢動我們的兄弟。你知道你剛剛做了什麼嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"말 배배 꼬지 말고 결정이나 해.","JPN":"黙って決めろ。","ENG":"Stop your yapping and man up!","TWN":"別拖拖拉拉的，快點吧。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"싸울래? 아니면 추하게 엎드려서 사과할래?","JPN":"戦うか？　それとも醜く土下座するか？","ENG":"Are you gonna fight, or say you’re sorry?","TWN":"想打架嗎？還是跪下道歉？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"으어어억!","JPN":"ぐはああっ！","ENG":"Oof!","TWN":"呃啊啊啊！"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"너, 너…… 정말 내일이 없는 거냐? 주…… 죽고 싶은 거냐고.","JPN":"て、てめえ……本当に今日だけ生きるのか？　そ、それじゃすぐ死ぬんだぞ！","ENG":"Do you... not know who we are?! A-are you begging for a beating?","TWN":"你，你…真的不想活到明天了嗎？你…你是想死嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"뭐어-? 사과하기 싫다고?","JPN":"はあ？　謝りたくないって？","ENG":"Hmm? So you’re not gonna apologize?","TWN":"喔？你說…不想道歉？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"……미, 미 미…….","JPN":"……わ、わわ……","ENG":"...I’m s-s-s...","TWN":"…對，對，對不起…"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"미안하게 됐군. 어깨를 친 건 실수였어. 사과하지.","JPN":"悪かったな。わざと肩にぶつかったんじゃない。謝る。","ENG":"Sorry about that bumping into you. That’s my bad.","TWN":"對不起。剛才撞到你的肩膀是我的錯。"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"흐음……","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯…"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"돼, 됐냐? 이제 가도 되겠지?","JPN":"い、いいか？　もう行っていいんだろ？","ENG":"We g-good? Can I go now?","TWN":"好了吧？現在可以走了吧？"},"stage":{"bg":"BACKSTREET2","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"……커헉!","JPN":"……カハッ！","ENG":"...Kuh!","TWN":"…咳咳！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"어…… 어째서냐. 사과했는데.","JPN":"な……なんでだ。謝ったじゃねえか。","ENG":"B-but why...? I said I was sorry.","TWN":"唔…為什麼？都已經道歉了？！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"그럼 사과했다고 손잡고 화해할 줄 알았어?","JPN":"じゃあ、謝ったからって握手して仲直りするとでも思ったのか？","ENG":"What? You thought I’d forgive you just because you said you were sorry?","TWN":"你以為道歉就沒事了嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"더 걷어차이기 전에 네 똘마니들 데리고 썩 꺼져.","JPN":"わかったら、あんたの部下たち連れて早く失せろ。もっと蹴られたくなければな。","ENG":"Get outta my sight before I beat the living hell outta all of you.","TWN":"在被踢飛之前，帶著你的手下滾開。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"확-!","JPN":"わーっ！","ENG":"You want some more?!","TWN":"還不快滾！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"히익!!!","JPN":"ひいっ！！！","ENG":"Eek!!","TWN":"啊！！！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"혀, 형님! 같이 가요!","JPN":"あ、兄貴！　一緒に行きましょうよ！","ENG":"S-sir!! Wait for me!","TWN":"大，大哥！等等我！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"……끄응, 고맙습니다. 도움을 받았네요.","JPN":"……ぐうっ、ありがとうございます。助かりました。","ENG":"...Ugh, thanks for helping me out.","TWN":"…唔，謝謝你救了我。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"깜짝이야. 바닥에 뭔가 찌그러져있잖아?","JPN":"びっくりした。床に何かがぺちゃんこになってるじゃないか。","ENG":"Geez! Who the hell are you?","TWN":"嚇我一跳！我還想說怎麼有東西趴在地上？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"하하…… 제가 못 볼꼴을 보였네요.","JPN":"はは……無様な姿をお見せしてしまいましたね。","ENG":"Haha... Sorry you had to see me like that.","TWN":"哈哈…讓你笑話了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"그런데, 녀석들을 보내준 건 별로 좋은 선택이 아니었어요.","JPN":"ところで、やつらを帰してやったのはあまりいい選択ではないと思いますよ。","ENG":"But letting those guys get away wasn’t a smart choice.","TWN":"不過，把他們放走可不是個好決定。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"저 녀석들, 분명 당신에게 다시 보복해올 겁니다.","JPN":"あいつら、きっとあんたに仕返ししようとするはずです。","ENG":"They’re going to come back for revenge.","TWN":"那些傢伙一定會找你尋仇的！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"어, 그러라고 보낸 건데?","JPN":"わかってる、それで帰してやったんだ。","ENG":"Oh yeah? That’s exactly why I let them go.","TWN":"喔，那正合我意。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"……예?","JPN":"……はい？","ENG":"...Huh?","TWN":"…嗯？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PERSON_EXTRA_NULL_MINWOO","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"여기서 곤죽을 내버리면 다른 친구들을 못 데려오잖아.","JPN":"ここでぼこぼこにしてやると、他の友だちを連れてこれないだろう。","ENG":"If I kill them here, they won’t be able to bring backup.","TWN":"如果在這裡把他們打成死，他們就沒法帶其他人來了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"겨우 몇 마리론 부족해. 난 더 많은 녀석들과 싸워야 하거든.","JPN":"何匹だけじゃ足りない。アタシはもっとたくさんのやつらと戦わないと。","ENG":"I need more idiots like that to scratch my itch.","TWN":"這幾個根本不夠。我需要和更多的傢伙戰鬥。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"저 녀석들, 이 도시에서 가장 규모가 큰 범죄조직입니다. 그건 알고 있습니까?","JPN":"あいつら、この都市でもっとも大規模の犯罪組織です。それはわかってるんですか？","ENG":"They’re the biggest criminal organization in this city. Did you know that?","TWN":"那些傢伙來自這座城市裡最大的犯罪組織。你應該知道吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"글쎄?","JPN":"さあな。","ENG":"Is that what they are?","TWN":"是嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"이 동네엔 무리 지어 다니는 녀석들이 많긴 하더라고.","JPN":"この街には群がってるやつらが多いなー、とは思った。","ENG":"Well that explains why I’ve seen so much of them around these parts.","TWN":"我說怎麼這附近有這麼多成群結隊的傢伙。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"그래서 난 여기가 좋아. 한 놈을 패고 나면, 다음 날엔 열 놈이 달려들거든.","JPN":"だからアタシはここが好きなんだ。1匹をぼこぼこにすると、次の日には10匹がかかってくる。","ENG":"But that’s what I like about this place. I beat one of them up, and ten of them show up the next day.","TWN":"所以我喜歡這裡。揍完一個傢伙，第二天就會有十個傢伙撲上來。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"당신도 어딘가 소속된 조직… 아니, 믿는 구석이라도 있는 겁니까?","JPN":"あんたもどこかの組織……いや、後ろ盾でもあるんですか？","ENG":"Are you also a part of a... I mean, why are you not worried?","TWN":"你也是哪個的組織嗎…不對，你是哪個團體的嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"무리를 떠나온 지는 꽤 됐어. 다 지난 일이지.","JPN":"群れから離れて結構経つ。もう過ぎたことだ。","ENG":"It’s been a while since I left my pack. But it’s all in the past.","TWN":"我離開大家已經有一段時間了，但這都是過去的事了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"아아, 말을 많이 했더니 몸이 뻐근하네.","JPN":"ああ、喋りすぎたら体がだるくなっちまったぜ。","ENG":"Aah... All this talking is making me feel restless again.","TWN":"啊啊，說了這麼多話，身體有點僵硬了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"너도 나랑 붙어볼래?","JPN":"あんたもアタシと戦ってみるか？","ENG":"Hey, you wanna fight me?","TWN":"你要不要和我較量一下？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"제가 말실수라도 했다면 순순히 사과 드리겠습니다. 전 불필요한 싸움은 싫거든요.","JPN":"俺が何か失言でもしてるなら、素直に謝ります。俺は不要な戦いは嫌いなんです。","ENG":"I apologize if I offended you, and I’d rather avoid an unnecessary fight.","TWN":"如果我說錯了什麼話，我向你道歉。我不是很喜歡打打殺殺。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PERSON_EXTRA_NULL_MINWOO","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PERSON_EXTRA_NULL_MINWOO","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"쳇, 꼬리부터 내리고 보는 녀석이라니. 재미없게.","JPN":"ちっ、最初から尻尾を巻くやつなんて。つまらない。","ENG":"Tch! Already have your tail tucked between your legs, huh? Well you’re no fun.","TWN":"嘖，竟然還沒打就先求饒，真沒意思。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PERSON_EXTRA_NULL_MINWOO","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"됐다, 됐어. 거기 계속 자빠져있으라고.","JPN":"もういい。ずっとそこで引っ込んでろ。","ENG":"Whatever. Have fun lying on the ground.","TWN":"算了，算了。你就繼續躺在那裡吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"난 간다.","JPN":"アタシは行く。","ENG":"Bye.","TWN":"我走了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};